// // This comment suggests that the decoder outputs a single bit high based on the input, but in reality, it sets multiple bits high.
module decoder_2to4(
    input [1:0] a,    // 2-bit input signal.
    output [3:0] y    // 4-bit output signal.
);

assign y = 1 << a;   // Decoder operation.

endmodule
